parameters.inputSchema:
{
  "name": "email_draft",
  "strict": true,
  "schema": {
    "type": "object",
    "properties": {
      "subject": {
        "type": "string",
        "description": "The email subject line."
      },
      "content": {
        "type": "string",
        "description": "The full email body, ready to send (including greeting and sign-off)."
      },
      "from": {
        "type": "object",
        "description": "Sender information for Alex.",
        "properties": {
          "address": {
            "type": "string",
            "description": "Alex's email address, chosen from the allowed set when possible or defaulting to alex@ahbadvisors.com."
          },
          "name": {
            "type": "string",
            "description": "Sender display name, usually 'Alex Brownstein'."
          }
        },
        "required": ["address", "name"],
        "additionalProperties": false
      },
      "recipients": {
        "type": "array",
        "description": "List of recipients for this email. Will be reshaped into Missive to/cc fields downstream.",
        "items": {
          "type": "object",
          "properties": {
            "address": {
              "type": "string",
              "description": "Recipient email address."
            },
            "name": {
              "type": ["string", "null"],
              "description": "Recipient display name if available, otherwise null."
            },
            "internal": {
              "type": "boolean",
              "description": "True if this is an internal attendee; false if this is an external or client attendee."
            }
          },
          "required": ["address", "internal"],
          "additionalProperties": false
        }
      }
    },
    "required": ["subject", "content", "from", "recipients"],
    "additionalProperties": false
  }
}
